CREATE TABLE standard_quotas (
	id INTEGER NOT NULL,
	class_type VARCHAR(50) NOT NULL,
	quotas JSON NOT NULL,
	is_system BOOLEAN DEFAULT FALSE,
	name VARCHAR(100) NOT NULL,
	description VARCHAR(500) DEFAULT '',
	quota_type VARCHAR(20) NOT NULL DEFAULT 'nutrition',
	PRIMARY KEY (id)
);
INSERT INTO standard_quotas (id, class_type, quotas, is_system, name, description, quota_type) VALUES(1,'幼儿园大班','{"calories": 1400, "protein": 30, "fat": 40, "carbs": 210}',true,'幼儿园大班营养摄入标准','基于中国居民膳食营养素参考摄入量，适用于5-6岁幼儿园大班儿童参考标准。每日总能量摄入参考值：卡路里1400kcal、蛋白质30g、脂肪40g、碳水化合物210g。','nutrition');
CREATE TABLE users (
	id INTEGER NOT NULL, 
	username VARCHAR(50) NOT NULL, 
	hashed_password VARCHAR(255) NOT NULL, 
	is_active BOOLEAN, 
	role VARCHAR(20), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
INSERT INTO users VALUES(1,'admin','$2b$12$0ZI2YQAXITB48WMHK5QQae.RrweFZf0oCnalQKhuH7H/.xByxkvJm',1,'admin','2026-03-24 03:35:04',NULL);
CREATE TABLE menu_histories (
	id VARCHAR(50) NOT NULL, 
	user_id INTEGER NOT NULL, 
	name VARCHAR(100), 
	menu_data JSON, 
	metrics_data JSON, 
	config_data JSON, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
